public class RestaurantApplicationDocument extends BaseAuditEntity {@Id private UUID id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="application_id") private RestaurantPartnerApplication application; @Enumerated(EnumType.STRING) @Column(nullable=false) private ApplicationDocumentType documentType; private String documentNumber; private String storageKey; @Column(nullable=false) private String fileUrl; private String fileName; private String mimeType; private Long fileSize; @Enumerated(EnumType.STRING) @Column(nullable=false) private DocumentVerificationStatus verificationStatus; private String rejectionReason; private LocalDate issuedAt; private LocalDate expiresAt; private Instant verifiedAt; private UUID verifiedByUserId; @Version private long version; @PrePersist void id(){if(id==null)id=UUID.randomUUID();}}
